if (planTool === 'masking-region') {
  // KRN-10: two-click rectangular masking-region fallback while
  // SKT-01 sketch sessions extend to the `masking_region` kind.
  const d = draftRef.current;
  if (!d || d.kind !== 'masking-region') {
    draftRef.current = { kind: 'masking-region', sx: sp.xMm, sy: sp.yMm };
    bumpGeom((x) => x + 1);
    return;
  }
  if (Math.hypot(sp.xMm - d.sx, sp.yMm - d.sy) < 1) {
    draftRef.current = undefined;
    bumpGeom((x) => x + 1);
    return;
  }
  if (!activePlanViewId) {
    draftRef.current = undefined;
    bumpGeom((x) => x + 1);
    return;
  }
  const x0 = Math.min(d.sx, sp.xMm);
  const x1 = Math.max(d.sx, sp.xMm);
  const y0 = Math.min(d.sy, sp.yMm);
  const y1 = Math.max(d.sy, sp.yMm);
  onSemanticCommand({
    type: 'createMaskingRegion',
    hostViewId: activePlanViewId,
    boundaryMm: [
      { xMm: x0, yMm: y0 },
      { xMm: x1, yMm: y0 },
      { xMm: x1, yMm: y1 },
      { xMm: x0, yMm: y1 },
    ],
    fillColor: '#ffffff',
  });
  draftRef.current = undefined;
  bumpGeom((x) => x + 1);
  return;
}
if (planTool === 'align') {
  const { state: nextState, effect } = reduceAlign(alignStateRef.current, {
    kind: 'click',
    pointMm: sp,
  });
  alignStateRef.current = nextState;
  if (effect.commitAlign) {
    // Pick the nearest wall to the *target* click; align it to the
    // reference point that was first picked.
    const targetHit = nearestWallAt(
      elementsById,
      displayLevelId || undefined,
      effect.commitAlign.targetMm.xMm,
      effect.commitAlign.targetMm.yMm,
    );
    if (targetHit && targetHit.distMm < 900) {
      onSemanticCommand({
        type: 'alignElementToReference',
        targetWallId: targetHit.wall.id,
        referenceMm: effect.commitAlign.referenceMm,
      });
    }

