/* KRN-V3-06 — Plan region cut-plane overlays                               */
/* ────────────────────────────────────────────────────────────────────── */

export type PlanRegionOverlay = {
  id: string;
  name: string;
  levelId: string;
  outlineMm: { xMm: number; yMm: number }[];
  cutPlaneOffsetMm: number;
};

/**
 * Returns plan regions on the active level as overlay descriptors.
 * The canvas renders each region's dashed boundary and uses
 * `cutPlaneOffsetMm` to label the override cut plane in the Inspector.
 *
 * Point-in-polygon visibility: an element at height `h` (mm above the level)
 * is considered hidden at the parent cut-plane but visible within a region
 * when `h <= regionCutPlaneOffsetMm + levelElevationMm`.
 * The canvas uses this to drive live re-cut feedback (D2 / U1 invariant).
 */
export function extractPlanRegionOverlays(
  elementsById: Record<string, Element>,
  activeLevelId: string | undefined,
): PlanRegionOverlay[] {
  if (!activeLevelId) return [];
  const out: PlanRegionOverlay[] = [];
  for (const el of Object.values(elementsById)) {
    if (el.kind === 'plan_region' && el.levelId === activeLevelId) {
      out.push({
        id: el.id,
        name: el.name,
        levelId: el.levelId,
        outlineMm: el.outlineMm,
        cutPlaneOffsetMm: el.cutPlaneOffsetMm ?? -500,
      });
    }
  }
  return out;
}

/** Returns true if the world-mm point (xMm, yMm) lies inside the polygon. */
export function pointInPolygonMm(
  polygon: { xMm: number; yMm: number }[],
  xMm: number,
  yMm: number,
): boolean {
  let inside = false;
  const n = polygon.length;
  for (let i = 0, j = n - 1; i < n; j = i++) {
    const xi = polygon[i]!.xMm;
    const yi = polygon[i]!.yMm;
    const xj = polygon[j]!.xMm;
    const yj = polygon[j]!.yMm;
    if (yi > yMm !== yj > yMm && xMm < ((xj - xi) * (yMm - yi)) / (yj - yi) + xi) {
      inside = !inside;
    }
  }
  return inside;
}

